   996→	// because sometimes, istio-system tends to become the root config namespace.
   997→	// Destination rules are defined here for global purposes. We do not want these
   998→	// catch all destination rules to be the only dest rule, when processing CDS for
   999→	// proxies like the istio-ingressgateway or istio-egressgateway.
  1000→	// If there are no service specific dest rules, we will end up picking up the same
  1001→	// rules anyway, later in the code
  1002→
  1003→	// 1. select destination rule from proxy config namespace
  1004→	if proxyNameSpace != ps.Mesh.RootNamespace {
  1005→		// search through the DestinationRules in proxy's namespace first
  1006→		if ps.destinationRuleIndex.namespaceLocal[proxyNameSpace] != nil {
  1007→			if hostname, ok := MostSpecificHostMatch(service.Hostname,
  1008→				ps.destinationRuleIndex.namespaceLocal[proxyNameSpace].destRules,
  1009→			); ok {
  1010→				return ps.destinationRuleIndex.namespaceLocal[proxyNameSpace].destRules[hostname]
  1011→			}
  1012→		}
  1013→	} else {
  1014→		// If this is a namespace local DR in the same namespace, this must be meant for this proxy, so we do not
  1015→		// need to worry about overriding other DRs with *.local type rules here. If we ignore this, then exportTo=. in
  1016→		// root namespace would always be ignored
  1017→		if hostname, ok := MostSpecificHostMatch(service.Hostname,
  1018→			ps.destinationRuleIndex.rootNamespaceLocal.destRules,
  1019→		); ok {
  1020→			return ps.destinationRuleIndex.rootNamespaceLocal.destRules[hostname]
  1021→		}
  1022→	}
  1023→
  1024→	// 2. select destination rule from service namespace
  1025→	svcNs := service.Attributes.Namespace
  1026→
  1027→	// This can happen when finding the subset labels for a proxy in root namespace.
  1028→	// Because based on a pure cluster's fqdn, we do not know the service and
  1029→	// construct a fake service without setting Attributes at all.
  1030→	if svcNs == "" {
  1031→		for _, svc := range ps.servicesExportedToNamespace(proxyNameSpace) {
  1032→			if service.Hostname == svc.Hostname && svc.Attributes.Namespace != "" {
  1033→				svcNs = svc.Attributes.Namespace
